import React, { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { profileAPI, mentorsAPI, quizAPI } from '../../services/api';
import './Progress.css';

const Progress = () => {
  const [progress, setProgress] = useState({
    quizCompleted: 0,
    profileCompleted: 0,
    skillsAdded: 0,
    mentorsConnected: 0,
    coursesEnrolled: 0
  });
  const [loading, setLoading] = useState(true);
  const { user } = useAuth();

  useEffect(() => {
    fetchProgress();
  }, [user]);

  const fetchProgress = async () => {
    setLoading(true);
    try {
      console.log('🔄 Fetching progress data...');
      
      let quizCompleted = 0;
      let profileCompleted = 0;
      let skillsAdded = 0;
      let mentorsConnected = 0;
      let coursesEnrolled = 0;

      // 1. Check Quiz Completion
      try {
        const quizHistory = await quizAPI.getHistory();
        console.log('📝 Quiz history:', quizHistory);
        if (quizHistory.success && quizHistory.history && quizHistory.history.length > 0) {
          quizCompleted = 100;
          console.log('✅ Quiz completed found in history');
        } else {
          // Fallback to user data
          quizCompleted = (user?.quizResults?.length > 0) ? 100 : 0;
          console.log('📝 Quiz status from user data:', quizCompleted);
        }
      } catch (quizError) {
        console.log('❌ Quiz API error, using user data');
        quizCompleted = (user?.quizResults?.length > 0) ? 100 : 0;
      }

      // 2. Check Profile Completion
      try {
        const profileResponse = await profileAPI.getProfile();
        console.log('👤 Profile response:', profileResponse);
        
        if (profileResponse && profileResponse.user) {
          const userData = profileResponse.user;
          profileCompleted = calculateProfileCompletion(userData.profile || {});
          skillsAdded = calculateSkillsProgress(userData.profile?.skills || []);
          console.log('✅ Profile data from API');
        } else {
          profileCompleted = calculateProfileCompletion(user?.profile || {});
          skillsAdded = calculateSkillsProgress(user?.profile?.skills || []);
          console.log('⚠️ Using cached profile data');
        }
      } catch (profileError) {
        console.log('❌ Profile API error, using cached data');
        profileCompleted = calculateProfileCompletion(user?.profile || {});
        skillsAdded = calculateSkillsProgress(user?.profile?.skills || []);
      }

      // 3. Check Mentor Connections
      try {
        const mentorResponse = await mentorsAPI.getMyRequests();
        console.log('👥 Mentor requests:', mentorResponse);
        
        if (mentorResponse.success && mentorResponse.requests) {
          const acceptedMentors = mentorResponse.requests.filter(
            req => req.status === 'accepted'
          ).length;
          mentorsConnected = Math.min((acceptedMentors / 3) * 100, 100);
          console.log(`✅ Found ${acceptedMentors} accepted mentor requests`);
        } else {
          mentorsConnected = 0;
          console.log('❌ No mentor requests data');
        }
      } catch (mentorError) {
        console.log('❌ Mentor API error:', mentorError);
        mentorsConnected = 0;
      }

      // 4. Course Enrollment (Mock data for now - you can implement later)
      coursesEnrolled = 0; // You can add course tracking when you implement courses API

      const progressData = {
        quizCompleted,
        profileCompleted,
        skillsAdded,
        mentorsConnected,
        coursesEnrolled
      };
      
      console.log('🎯 Final progress data:', progressData);
      setProgress(progressData);
      
    } catch (error) {
      console.error('❌ Error in fetchProgress:', error);
      // Fallback to basic calculation from user data
      const fallbackProgress = calculateProgressFromUser(user);
      setProgress(fallbackProgress);
    } finally {
      setLoading(false);
    }
  };

  const calculateProgressFromUser = (userData) => {
    const quizCompleted = (userData?.quizResults?.length > 0) ? 100 : 0;
    const profileCompleted = calculateProfileCompletion(userData?.profile || {});
    const skillsAdded = calculateSkillsProgress(userData?.profile?.skills || []);
    
    return {
      quizCompleted,
      profileCompleted,
      skillsAdded,
      mentorsConnected: 0,
      coursesEnrolled: 0
    };
  };

  const calculateProfileCompletion = (profile) => {
    if (!profile) return 0;
    
    let completed = 0;
    const fields = [
      { key: 'bio', check: (val) => val && val.trim().length > 0 },
      { key: 'education', check: (val) => val && val.trim().length > 0 },
      { key: 'experience', check: (val) => val !== undefined && val !== null },
      { key: 'skills', check: (val) => val && val.length > 0 },
      { key: 'interests', check: (val) => val && val.length > 0 }
    ];

    fields.forEach(field => {
      if (field.check(profile[field.key])) {
        completed++;
        console.log(`✅ ${field.key} completed`);
      }
    });

    const percentage = Math.round((completed / fields.length) * 100);
    console.log(`📊 Profile completion: ${completed}/${fields.length} = ${percentage}%`);
    return percentage;
  };

  const calculateSkillsProgress = (skills) => {
    const skillsCount = skills.length;
    const progress = Math.min((skillsCount / 5) * 100, 100);
    console.log(`🛠️ Skills progress: ${skillsCount} skills = ${progress}%`);
    return progress;
  };

  const getOverallProgress = () => {
    const values = Object.values(progress);
    const overall = Math.round(values.reduce((a, b) => a + b, 0) / values.length);
    console.log('🎯 Overall progress:', overall);
    return overall;
  };

  const getProgressColor = (percentage) => {
    if (percentage >= 80) return '#10b981'; // Green
    if (percentage >= 50) return '#f59e0b'; // Yellow
    return '#ef4444'; // Red
  };

  const refreshProgress = () => {
    console.log('🔄 Manually refreshing progress...');
    fetchProgress();
  };

  // Test function to simulate progress (remove in production)
  const testProgressUpdate = () => {
    console.log('🧪 Testing progress update...');
    // Simulate completing a quiz
    setProgress(prev => ({
      ...prev,
      quizCompleted: 100,
      mentorsConnected: Math.min(prev.mentorsConnected + 33, 100)
    }));
  };

  if (!user) {
    return (
      <div className="progress-container">
        <div className="container">
          <div className="auth-required">
            <h2>Authentication Required</h2>
            <p>Please log in to view your progress.</p>
          </div>
        </div>
      </div>
    );
  }

  if (loading) {
    return (
      <div className="progress-container">
        <div className="container">
          <div className="loading">
            <div className="spinner"></div>
            Loading your progress...
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="progress-container">
      <div className="container">
        <div className="progress-header">
          <h1>📊 Your Progress</h1>
          <p>Track your career development journey</p>
          <div className="progress-actions-top">
            <button 
              onClick={refreshProgress}
              className="btn btn-secondary refresh-btn"
            >
              🔄 Refresh Progress
            </button>
            {/* Remove this test button in production */}
            <button 
              onClick={testProgressUpdate}
              className="btn btn-test"
              style={{marginLeft: '10px', background: '#8b5cf6', color: 'white'}}
            >
              🧪 Test Update
            </button>
          </div>
        </div>

        {/* Overall Progress */}
        <div className="overall-progress">
          <div className="progress-card">
            <h2>Overall Completion</h2>
            <div className="progress-circle">
              <div 
                className="circle" 
                style={{ 
                  background: `conic-gradient(${getProgressColor(getOverallProgress())} ${getOverallProgress() * 3.6}deg, #e2e8f0 0deg)` 
                }}
              >
                <span className="progress-value">{getOverallProgress()}%</span>
              </div>
            </div>
            <p>Complete all sections to maximize your career guidance</p>
            <div className="progress-stats">
              <div className="stat">
                <span className="stat-value">{Math.round(progress.quizCompleted)}%</span>
                <span className="stat-label">Quiz</span>
              </div>
              <div className="stat">
                <span className="stat-value">{Math.round(progress.profileCompleted)}%</span>
                <span className="stat-label">Profile</span>
              </div>
              <div className="stat">
                <span className="stat-value">{Math.round(progress.mentorsConnected)}%</span>
                <span className="stat-label">Mentors</span>
              </div>
            </div>
          </div>
        </div>

        {/* Detailed Progress */}
        <div className="detailed-progress">
          <div className="progress-item">
            <div className="progress-info">
              <h3>Career Assessment</h3>
              <span className="progress-percentage">{Math.round(progress.quizCompleted)}%</span>
            </div>
            <div className="progress-bar">
              <div 
                className="progress-fill" 
                style={{ 
                  width: `${progress.quizCompleted}%`,
                  backgroundColor: getProgressColor(progress.quizCompleted)
                }}
              ></div>
            </div>
            <p className="progress-description">
              {progress.quizCompleted === 100 
                ? '✅ Quiz completed! Check your results in Dashboard.' 
                : 'Take the career quiz to discover your ideal career path.'
              }
            </p>
            {progress.quizCompleted === 0 && (
              <button 
                onClick={() => window.location.href = '/quiz'}
                className="btn btn-small"
              >
                Take Quiz Now
              </button>
            )}
          </div>

          <div className="progress-item">
            <div className="progress-info">
              <h3>Profile Completion</h3>
              <span className="progress-percentage">{Math.round(progress.profileCompleted)}%</span>
            </div>
            <div className="progress-bar">
              <div 
                className="progress-fill" 
                style={{ 
                  width: `${progress.profileCompleted}%`,
                  backgroundColor: getProgressColor(progress.profileCompleted)
                }}
              ></div>
            </div>
            <p className="progress-description">
              {progress.profileCompleted === 100 
                ? '✅ Profile fully completed!' 
                : 'Complete your profile for personalized recommendations.'
              }
            </p>
            {progress.profileCompleted < 100 && (
              <button 
                onClick={() => window.location.href = '/profile'}
                className="btn btn-small"
              >
                Complete Profile
              </button>
            )}
          </div>

          <div className="progress-item">
            <div className="progress-info">
              <h3>Skills Development</h3>
              <span className="progress-percentage">{Math.round(progress.skillsAdded)}%</span>
            </div>
            <div className="progress-bar">
              <div 
                className="progress-fill" 
                style={{ 
                  width: `${progress.skillsAdded}%`,
                  backgroundColor: getProgressColor(progress.skillsAdded)
                }}
              ></div>
            </div>
            <p className="progress-description">
              {progress.skillsAdded >= 80 
                ? '✅ Great job building your skills!' 
                : 'Add more skills to your profile to get better career matches.'
              }
            </p>
          </div>

          <div className="progress-item">
            <div className="progress-info">
              <h3>Mentor Connections</h3>
              <span className="progress-percentage">{Math.round(progress.mentorsConnected)}%</span>
            </div>
            <div className="progress-bar">
              <div 
                className="progress-fill" 
                style={{ 
                  width: `${progress.mentorsConnected}%`,
                  backgroundColor: getProgressColor(progress.mentorsConnected)
                }}
              ></div>
            </div>
            <p className="progress-description">
              {progress.mentorsConnected > 0 
                ? `✅ Connected with mentors! Keep building relationships.` 
                : 'Connect with mentors to accelerate your career growth.'
              }
            </p>
            <button 
              onClick={() => window.location.href = '/mentors'}
              className="btn btn-small"
            >
              Find Mentors
            </button>
          </div>

          <div className="progress-item">
            <div className="progress-info">
              <h3>Learning Progress</h3>
              <span className="progress-percentage">{Math.round(progress.coursesEnrolled)}%</span>
            </div>
            <div className="progress-bar">
              <div 
                className="progress-fill" 
                style={{ 
                  width: `${progress.coursesEnrolled}%`,
                  backgroundColor: getProgressColor(progress.coursesEnrolled)
                }}
              ></div>
            </div>
            <p className="progress-description">
              Enroll in courses to develop skills for your target career.
            </p>
            <button 
              onClick={() => window.location.href = '/courses'}
              className="btn btn-small"
            >
              Explore Courses
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Progress;
